`// HTTP Event Listener registered for ${b.getValue('eventType')}
window.__httpEventListeners = window.__httpEventListeners || [];
window.__httpEventListeners.push({
  type: '${b.getValue('eventType')}',
  pattern: '${b.getValue('urlPattern')}',
  target: '${b.getValue('targetVar')}',
  handler: function(data) {
    window['${b.getValue('targetVar')}'] = data;
    ${b.handlerBlocks?.map(c => `
    // Execute child blocks
    ${c.export?.javascript ? c.export.javascript(c) : ''}`).join('
') || '// No handler code'}
  }
});`
